sql:
SELECT COUNT(*) AS Total_Units, AVG(capacity) AS Avg_Energy_Capacity
FROM storage_units
HAVING AVG(capacity) > 100;

SELECT facility_name
FROM facilities
WHERE facility_id > 5 AND facility_id <= 10;

SELECT unit_id, AVG(storage_0 + storage_1 + storage_2 + storage_3 + storage_4 + storage_5) AS average_energy_level
FROM energy_readings
GROUP BY unit_id;

external_knowledge:
- 'a certain area' refers to 'your_location';
- 'more than a moderate amount of energy activity' is defined as having more than 5 energy readings;
- 'the last couple of weeks' refers to the past 14 days.

sql:
